+                    .get("id")
+                    .and_then(Value::as_str)
+                    .unwrap_or_default()
+                    .to_string();
+                if model_id.is_empty() {
+                    continue;
+                }
+                let model_name = model_spec
+                    .get("name")
+                    .and_then(Value::as_str)
+                    .map(ToString::to_string)
+                    .unwrap_or_else(|| model_id.clone());
+                let model_api = model_spec
+                    .get("api")
+                    .and_then(Value::as_str)
