+                        },
+                        context_window,
+                        max_tokens,
+                        headers: HashMap::new(),
+                    },
+                    api_key: resolved_key.clone(),
+                    headers: HashMap::new(),
+                    auth_header: true,
+                    compat: None,
+                });
+            }
+        }
+        entries
+    }
